import React, { useEffect, useState } from 'react'
import { Link, useLocation, useNavigate } from 'react-router-dom'
// import { FaRegEyeSlash } from "react-icons/fa6";
// import { FaRegEye } from "react-icons/fa6";
import toast from 'react-hot-toast';

const ResetPassword = () => {
    const location = useLocation()
    const navigate = useNavigate()
    const [data, setData] = useState({
        email: "",
        newPassword: "",
        confirmPassword: ""
    })
    const [showPassword, setShowPassword] = useState(false)
    const [showConfirmPassword, setShowConfirmPassword] = useState(false)
    const [isLoading, setIsLoading] = useState(false)

    const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
    const validValue = Object.values(data).every(el => el) && data.newPassword === data.confirmPassword

    useEffect(() => {
        if (!(location?.state?.data?.success)) {
            navigate("/")
        }

        if (location?.state?.email) {
            setData((prev) => {
                return {
                    ...prev,
                    email: location?.state?.email
                }
            })
        }
    }, [location, navigate])

    const handleChange = (e) => {
        const { name, value } = e.target

        setData((prev) => {
            return {
                ...prev, [name]: value
            }
        })
    }

    console.log("data reset password", data)

    const handleSubmit = async (e) => {
        e.preventDefault()
        
        // Validation
        if (data.newPassword !== data.confirmPassword) {
            toast.error('Passwords do not match')
            return
        }

        if (data.newPassword.length < 6) {
            toast.error('Password must be at least 6 characters long')
            return
        }

        setIsLoading(true)

        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/reset-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    email: data.email,
                    newPassword: data.newPassword,
                    token: location?.state?.data?.resetToken
                })
            })

            const result = await response.json()

            if (response.status === 404) {
                toast.error('Password reset feature is currently under development. Please contact support.')
                return
            }

            if (!response.ok) {
                toast.error(result.message || 'Failed to reset password')
                return
            }

            if (result.success) {
                toast.success('Password reset successfully!')
                navigate("/")
                setData({
                    email: "",
                    newPassword: "",
                    confirmPassword: ""
                })
            }

        } catch (error) {
            console.error('Reset password error:', error)
            if (error.message.includes('Failed to fetch')) {
                toast.error('Cannot connect to server. Please check your internet connection.')
            } else {
                toast.error('Failed to reset password. Please try again.')
            }
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <section className='w-full container mx-auto px-2'>
            <div className='bg-white my-4 w-full max-w-lg mx-auto rounded p-7'>
                <p className='font-semibold text-lg'>Enter Your New Password</p>
                <form className='grid gap-4 py-4' onSubmit={handleSubmit}>
                    <div className='grid gap-1'>
                        <label htmlFor="newPassword">New Password :</label>
                        <div className='bg-blue-50 p-2 border rounded flex items-center'>
                            <input
                                type={showPassword ? "text" : "password"}
                                id='newPassword'
                                autoFocus
                                className='w-full outline-none'
                                name="newPassword"
                                value={data.newPassword}
                                onChange={handleChange}
                                placeholder='Enter your new password'
                                required
                            />
                            <div onClick={() => setShowPassword(prev => !prev)} className='cursor-pointer'>
                                {showPassword ? <FaRegEye /> : <FaRegEyeSlash />}
                            </div>
                        </div>
                    </div>
                    
                    <div className='grid gap-1'>
                        <label htmlFor="confirmPassword">Confirm Password :</label>
                        <div className='bg-blue-50 p-2 border rounded flex items-center'>
                            <input
                                type={showConfirmPassword ? "text" : "password"}
                                id='confirmPassword'
                                className='w-full outline-none'
                                name="confirmPassword"
                                value={data.confirmPassword}
                                onChange={handleChange}
                                placeholder='Confirm your new password'
                                required
                            />
                            <div onClick={() => setShowConfirmPassword(prev => !prev)} className='cursor-pointer'>
                                {showConfirmPassword ? <FaRegEye /> : <FaRegEyeSlash />}
                            </div>
                        </div>
                    </div>

                    <button 
                        disabled={!validValue || isLoading} 
                        className={`${validValue && !isLoading ? "bg-violet-800 hover:bg-violet-700" : "bg-gray-500"} text-white py-2 rounded font-semibold my-2 tracking-wide`}
                    >
                        {isLoading ? 'Resetting Password...' : 'Reset Password'}
                    </button>
                </form>

                <p>
                    Remember your password? <Link to={"/"}
                        className='font-semibold text-purple-700
                    hover:text-purple-800'>Back to Login</Link>
                </p>
            </div>
        </section>
    )
}

export default ResetPassword
